namespace sv_49a3f23cd0ba48c397454fafd4a01b5c.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@* Displays step progress bar with clickable completed steps *@

<nav class="step-indicator mb-4" aria-label="Application steps">
    <ol class="d-flex list-unstyled justify-content-between p-0 m-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i;
            var state = GetStepState(step);
            <li class="step-item flex-fill text-center @state">
                @if (state == "completed")
                {
                    <button class="btn btn-link step-btn p-0 text-decoration-none" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle">✓</span>
                        <span class="step-label d-block mt-1">@StepNames[step]</span>
                    </button>
                }
                else
                {
                    <div class="step-btn p-0">
                        <span class="step-circle">@(step + 1)</span>
                        <span class="step-label d-block mt-1">@StepNames[step]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public IReadOnlySet<int> CompletedSteps { get; set; } = default!;
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];

    private string GetStepState(int step)
    {
        if (step == CurrentStep) return "active";
        if (CompletedSteps.Contains(step)) return "completed";
        return "dimmed";
    }
}

@* Single work entry with company, title, dates, description *@

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input class="form-control" value="@Company" @onchange="e => Update(company: e.Value?.ToString())" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input class="form-control" value="@Title" @onchange="e => Update(title: e.Value?.ToString())" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@StartDate?.ToString("yyyy-MM-dd")"
                       @onchange="e => Update(startDate: DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null)" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@EndDate?.ToString("yyyy-MM-dd")" disabled="@IsCurrent"
                       @onchange="e => Update(endDate: DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null)" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" checked="@IsCurrent" id="current-@Index"
                           @onchange="e => OnIsCurrentChanged.InvokeAsync((bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="current-@Index">I currently work here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Description"
                          @onchange="e => Update(description: e.Value?.ToString())"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public int Index { get; set; }
    [Parameter] public string Company { get; set; } = "";
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public DateTime? StartDate { get; set; }
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public string Description { get; set; } = "";
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback<bool> OnIsCurrentChanged { get; set; }
    [Parameter] public EventCallback<(string Company, string Title, DateTime? StartDate, DateTime? EndDate, string Description)> OnChanged { get; set; }

    private void Update(string? company = null, string? title = null, DateTime? startDate = null, DateTime? endDate = null, string? description = null)
    {
        OnChanged.InvokeAsync((
            company ?? Company,
            title ?? Title,
            startDate ?? StartDate,
            endDate ?? EndDate,
            description ?? Description
        ));
    }
}

