</div>

@code {
    [Parameter] public List<EntryModel> Entries { get; set; } = [new()];
    [Parameter] public EventCallback<List<EntryModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    public class EntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime? StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private void AddEntry() => Entries.Add(new EntryModel());

    private void RemoveEntry(int index) => Entries.RemoveAt(index);

    private void UpdateIsCurrent(int index, bool value)
    {
        Entries[index].IsCurrent = value;
        if (value) Entries[index].EndDate = null;
    }

    private void UpdateEntry(int index, (string Company, string Title, DateTime? StartDate, DateTime? EndDate, string Description) v)
    {
        var entry = Entries[index];
        entry.Company = v.Company;
        entry.Title = v.Title;
        entry.StartDate = v.StartDate;
        entry.EndDate = v.EndDate;
        entry.Description = v.Description;
