@using sv_49a3f23cd0ba48c397454fafd4a01b5c.Models

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Refs.Count; i++)
{
    var idx = i;
    var r = Refs[idx];
    <ReferenceForm Index="idx"
                   Name="@r.Name"
                   Relationship="@r.Relationship"
                   Email="@r.Email"
                   Phone="@r.Phone"
                   CanRemove="@(Refs.Count > 2)"
                   OnRemove="() => RemoveRef(idx)"
                   OnChanged="v => UpdateRef(idx, v)" />
}

@if (Refs.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddRef">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<RefModel> Refs { get; set; } = [new(), new()];
    [Parameter] public EventCallback<List<RefModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    public class RefModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }

    private void AddRef() { if (Refs.Count < 3) Refs.Add(new RefModel()); }

    private void RemoveRef(int index) { if (Refs.Count > 2) Refs.RemoveAt(index); }

    private void UpdateRef(int index, (string Name, string Relationship, string Email, string Phone) v)
    {
        var r = Refs[index];
        r.Name = v.Name;
        r.Relationship = v.Relationship;
        r.Email = v.Email;
        r.Phone = v.Phone;
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;
        foreach (var r in Refs)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All reference fields are required.";
                return;
            }
        }
        await OnNext.InvokeAsync(Refs);
    }
}

