@page "/apply"
@using sv_49a3f23cd0ba48c397454fafd4a01b5c.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep FullName="@personalInfo.FullName"
                                  Email="@personalInfo.Email"
                                  Phone="@personalInfo.Phone"
                                  Address="@personalInfo.Address"
                                  ApplicationService="ApplicationService"
                                  OnNext="HandlePersonalNext" />
                break;

            case 1:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="HandleWorkNext"
                                 OnBack="() => GoToStep(0)" />
                break;

            case 2:
                <ReferencesStep Refs="references"
                                OnNext="HandleRefsNext"
                                OnBack="() => GoToStep(1)" />
                break;

            case 3:
                <CoverLetterStep CoverLetter="@coverLetter"
                                 OnNext="HandleCoverNext"
                                 OnBack="() => GoToStep(2)" />
                break;

            case 4:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="@coverLetter"
                            ApplicationService="ApplicationService"
                            OnEdit="GoToStep"
                            OnBack="() => GoToStep(3)" />
                break;
        }
    </div>
</div>

@code {
    private int currentStep;
    private HashSet<int> completedSteps = new();

    private PersonalInfo personalInfo = new("", "", "", "");
    private List<WorkHistoryStep.EntryModel> workEntries = [new()];
    private List<ReferencesStep.RefModel> references = [new(), new()];
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        if (step == currentStep) return;
        if (step < currentStep || completedSteps.Contains(step))
        {
            currentStep = step;
        }
    }

    private void HandlePersonalNext(PersonalInfo info)
    {
        personalInfo = info;
        completedSteps.Add(0);
        currentStep = 1;
    }

    private void HandleWorkNext(List<WorkHistoryStep.EntryModel> entries)
    {
        workEntries = entries;
        completedSteps.Add(1);
        currentStep = 2;
    }

    private void HandleRefsNext(List<ReferencesStep.RefModel> refs)
    {
        references = refs;
        completedSteps.Add(2);
        currentStep = 3;
    }

    private void HandleCoverNext(string text)
    {
        coverLetter = text;
        completedSteps.Add(3);
        currentStep = 4;
    }
}

.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
}

.step-item + .step-item::before {
    content: "";
    position: absolute;
    top: 18px;
    left: -50%;
    width: 100%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed + .step-item::before,
.step-item.active + .step-item.completed::before {
    background-color: #198754;
}

.step-item.completed + .step-item.active::before {
    background-color: #198754;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.9rem;
    position: relative;
    z-index: 1;
}

.step-label {
    font-size: 0.8rem;
}

/* Active step */
.step-item.active .step-circle {
    background-color: #0d6efd;
    color: white;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

/* Completed step */
.step-item.completed .step-circle {
    background-color: #198754;
    color: white;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.completed .step-btn {
    cursor: pointer;
    color: inherit;
}

/* Dimmed (future) step */
.step-item.dimmed .step-circle {
    background-color: #e9ecef;
    color: #6c757d;
}

.step-item.dimmed .step-label {
    color: #adb5bd;
}

